Write-Host "[b/q] salir/volver | m = mantenimiento | ? = ayuda | Enter = refrescar" -ForegroundColor DarkGray
param([string]$ProjectPath="")
$ErrorActionPreference="Stop"
function W($m,$c="White"){Write-Host $m -ForegroundColor $c}
function ActiveProject([string]$p){ if($p -and (Test-Path $p)){return $p}; $j="C:\ENGREMIAT_CORE\data\desktop-terminal-operator\active-project.json"; $t="C:\ENGREMIAT_CORE\data\desktop-terminal-operator\active-project.txt"; if(Test-Path $j){$x=Get-Content $j -Raw|ConvertFrom-Json; if($x.active_project -and (Test-Path ([string]$x.active_project))){return [string]$x.active_project}}; if(Test-Path $t){$y=(Get-Content $t -Raw).Trim(); if(Test-Path $y){return $y}}; throw "active_project_missing"}
function ReadModule($dir){$mj=Join-Path $dir "module.json"; if(Test-Path $mj){try{return Get-Content $mj -Raw|ConvertFrom-Json}catch{}}; return [pscustomobject]@{id=(Split-Path $dir -Leaf);name=(Split-Path $dir -Leaf);type="operational_module";status="ACTIVO";relations=@()}}
$ProjectPath=ActiveProject $ProjectPath; $modsDir=Join-Path $ProjectPath "MODULOS"; New-Item -ItemType Directory -Force -Path $modsDir|Out-Null; $graphDir=Join-Path $ProjectPath "GRAFO"; $dedDir=Join-Path $graphDir "MODULOS"; New-Item -ItemType Directory -Force -Path $graphDir,$dedDir|Out-Null; $mods=Get-ChildItem $modsDir -Directory -ErrorAction SilentlyContinue|Sort-Object Name; $nodes=@(); $edges=@(); foreach($m in $mods){$j=ReadModule $m.FullName; $id=if($j.id){[string]$j.id}else{$m.Name}; $title=if($j.name){[string]$j.name}else{$m.Name}; $status=if($j.status){[string]$j.status}else{"ACTIVO"}; $kind=if($j.type){[string]$j.type}else{"operational_module"}; $nodes+=[pscustomobject]@{id=$id;title=$title;path=$m.FullName;kind=$kind;status=$status}; $edges+=[pscustomobject]@{from="PROJECT";to=$id;relation="contains_module"}; if($j.relations){foreach($r in @($j.relations)){if($r.to){$edges+=[pscustomobject]@{from=$id;to=[string]$r.to;relation=if($r.relation){[string]$r.relation}else{"relates_to"}}}}}}
$global=@("# GRAFO GLOBAL DEL PROYECTO","","Proyecto: $ProjectPath","","## Modulos detectados"); foreach($n in $nodes){$global+="- $($n.id) | $($n.status) | $($n.path)"}; $global+=""; $global+="## Relaciones"; foreach($e in $edges){$global+="- $($e.from) -> $($e.to) : $($e.relation)"}; Set-Content (Join-Path $graphDir "GRAFO_GLOBAL.md") $global -Encoding UTF8; foreach($n in $nodes){$local=@("# $($n.title)","","- id: $($n.id)","- status: $($n.status)","- path: $($n.path)","","## Relaciones entrantes y salientes"); foreach($e in $edges|?{$_.from -eq $n.id -or $_.to -eq $n.id}){$local+="- $($e.from) -> $($e.to) : $($e.relation)"}; Set-Content (Join-Path $dedDir (($n.id -replace "[^\w\.-]","_")+".md")) $local -Encoding UTF8}; [pscustomobject]@{generated_at=(Get-Date).ToString("s");project=$ProjectPath;nodes=$nodes;edges=$edges}|ConvertTo-Json -Depth 30|Set-Content (Join-Path $graphDir "GRAFO_GLOBAL.json") -Encoding UTF8; W "OK graph_refreshed modules=$($nodes.Count) edges=$($edges.Count)" Green
